import React, { useEffect, useRef, useState } from 'react';
import '../styles/GameCanvas.css';
import { AWS_ICON_CATEGORIES, SERVICE_MAPPINGS } from '../services/IconResolver';

// AWS Assets
const S3_BUCKET_URL = 'https://hackthon-backend-files-ep-2024.s3.amazonaws.com';
const ICONS_BASE_PATH = '/amazon-icons-set/Architecture-Service-Icons_06072024';
const S3_ROCKET_PATH = `${S3_BUCKET_URL}/games/rocket`;
const DEFAULT_ROCKET = `${S3_ROCKET_PATH}/rocket1.png`;
const FIREBALL_PATH = `${S3_BUCKET_URL}/games/bullet/fireball.png`;

const GameCanvas = () => {
  const [timeLeft, setTimeLeft] = useState(60);
  const [score, setScore] = useState(0);
  const [currentInstruction, setCurrentInstruction] = useState(null);
  const [selectedRocket, setSelectedRocket] = useState(localStorage.getItem('selectedRocket') || DEFAULT_ROCKET);
  const [gameStarted, setGameStarted] = useState(false);
  const [gameOver, setGameOver] = useState(false);

  const canvasRef = useRef(null);
  const iconsRef = useRef([]);
  const bulletsRef = useRef([]);
  const rocketImage = useRef(new Image());
  const fireballImage = new Image();
  fireballImage.src = FIREBALL_PATH;

  useEffect(() => {
    rocketImage.current.src = selectedRocket;
  }, [selectedRocket]);

  // **Consolidated Function: Start new category when game starts OR icons deplete**
  const NewCategoryMission = () => {
    if (!gameStarted || gameOver) return;

    console.log("Starting a new category mission...");
    iconsRef.current = [];

    // Select a random AWS category
    const categories = Object.keys(AWS_ICON_CATEGORIES);
    const randomCategory = categories[Math.floor(Math.random() * categories.length)];
    const displayName = randomCategory.replace('_', ' ');

    setCurrentInstruction({
      text: `Shoot the ${displayName} icons!`,
      category: AWS_ICON_CATEGORIES[randomCategory],
      displayName
    });

    // Get icons from selected category
    const categoryIcons = Object.entries(SERVICE_MAPPINGS)
      .filter(([_, path]) => path.includes(AWS_ICON_CATEGORIES[randomCategory]))
      .map(([name, path]) => ({
        path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
        name,
        category: randomCategory
      }));

    // Ensure at least 4 icons appear (repeat if needed)
    const selectedIcons = [...categoryIcons, ...categoryIcons].slice(0, 4);

    // Place icons randomly on canvas
    const positions = [];
    selectedIcons.forEach((iconInfo) => {
      let x;
      do {
        x = Math.floor(Math.random() * (canvasRef.current.width - 50));
      } while (positions.some(pos => Math.abs(pos - x) < 50));
      positions.push(x);

      const iconImage = new Image();
      iconImage.src = iconInfo.path;

      iconsRef.current.push({
        x,
        y: -50,
        type: iconInfo.category,
        name: iconInfo.name,
        image: iconImage,
        hit: false
      });
    });

    console.log(`New Mission: Shoot ${displayName} icons!`);
  };

  // **Trigger a new category mission at game start & when icons are gone**
  useEffect(() => {
    if (gameStarted && !gameOver) {
      NewCategoryMission();
    }
  }, [gameStarted]);

  useEffect(() => {
    if (iconsRef.current.length === 0 && timeLeft > 0) {
      console.log("Icons depleted, loading new category...");
      NewCategoryMission();
    }
  }, [iconsRef.current]);

  // **Game Loop to Render & Update Everything**
  const gameLoop = () => {
    if (!gameStarted || gameOver || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw Rocket
    ctx.drawImage(rocketImage.current, 375, 550, 120, 120);

    // Draw icons & move them down
    iconsRef.current.forEach((icon) => {
      if (!icon.hit) {
        ctx.drawImage(icon.image, icon.x, icon.y, 50, 50);
        icon.y += 1; // Moving speed
      }
    });

    // Remove off-screen icons and trigger new mission if all are gone
    iconsRef.current = iconsRef.current.filter(icon => icon.y < canvas.height);
    if (iconsRef.current.length === 0 && timeLeft > 0) {
      NewCategoryMission();
    }

    // Draw bullets & move them up
    bulletsRef.current.forEach((bullet) => {
      ctx.drawImage(fireballImage, bullet.x, bullet.y, 20, 20);
      bullet.y -= 5;
    });

    bulletsRef.current = bulletsRef.current.filter(bullet => bullet.y > 0);

    requestAnimationFrame(gameLoop);
  };

  useEffect(() => {
    if (gameStarted) requestAnimationFrame(gameLoop);
  }, [gameStarted]);

  return (
    <div className="gameCanvas-container">
      <h1 className="gameCanvas-game-title">AWS Cloud Shooter</h1>
      <canvas ref={canvasRef} className="gameCanvas-game-canvas" />

      {!gameStarted && (
        <button onClick={() => setGameStarted(true)}>Start Game</button>
      )}

      {gameOver && (
        <div className="gameCanvas-game-over">
          <h3>Game Over!</h3>
          <button onClick={() => window.location.reload()}>Play Again</button>
        </div>
      )}

      {currentInstruction && (
        <div className="gameCanvas-mission-container">
          <h3 className="gameCanvas-mission-title">Current Mission</h3>
          <p>{currentInstruction.text}</p>
        </div>
      )}
    </div>
  );
};

export default GameCanvas;
